import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger
} from '@/components/ui/dialog'
import { Item, ItemContent, ItemDescription, ItemTitle } from '@/components/ui/item'
import { getTracksData, TrackData } from './mediabunny'
import { memo, useEffect, useState } from 'react'
import { formatBitrate, formatBytes, formatDuration, truncateTo2Decimals } from './utils'
import { usePlayerStaticContext } from './provider'

function TrackInfoField({ title, value }: { title: string; value: React.ReactNode }) {
  return (
    <Item>
      <ItemContent>
        <ItemTitle>{title}</ItemTitle>
        <ItemDescription>{value}</ItemDescription>
      </ItemContent>
    </Item>
  )
}

function getTrackInfoFields(track: TrackData) {
  const fields: { title: string; value: React.ReactNode }[] = [
    {
      title: 'Average bitrate',
      value: track.averageBitrate ? formatBitrate(track.averageBitrate) : 'N/A'
    },
    { title: 'Codec', value: track.codec ?? 'N/A' },
    { title: 'Codec string', value: track.codecParamString ?? 'N/A' },
    { title: 'Language', value: track.lang ?? 'N/A' }
  ]

  if (track.isVideo) {
    fields.push(
      {
        title: 'Frame rate',
        value: track.frameRate ? truncateTo2Decimals(track.frameRate) : 'N/A'
      },
      { title: 'Coded height', value: track.codedHeight ?? 'N/A' },
      { title: 'Coded width', value: track.codedWidth ?? 'N/A' },
      { title: 'Display height', value: track.displayHeight ?? 'N/A' },
      { title: 'Display width', value: track.displayWidth ?? 'N/A' }
    )
  }

  if (track.isAudio) {
    fields.push(
      { title: 'Sample rate', value: track.sampleRate ?? 'N/A' },
      { title: 'Channels', value: track.channels ?? 'N/A' }
    )
  }

  return fields
}

type InfoModalProps = {
  children?: React.ReactNode
  open?: boolean
  onOpenChange?: (open: boolean) => void
}

export const InfoModal = memo(function InfoModal({ children, open, onOpenChange }: InfoModalProps) {
  const { file, fileData } = usePlayerStaticContext()
  const [tracksData, setTracksData] = useState<TrackData[]>([])

  useEffect(() => {
    getTracksData(file).then((tracksData) => {
      setTracksData(tracksData)
    })
  }, [file])

  const hoverCardContentMap = {
    'Last modified': new Date(file.lastModified).toLocaleDateString(),
    Size: formatBytes(file.size),
    Format: fileData?.format.name,
    'MIME Type': fileData?.format.mimeType,
    Duration: fileData?.duration ? formatDuration(fileData.duration) : 'N/A',
    Artist: fileData?.metadataTags.artist,
    Album: fileData?.metadataTags.album,
    'Total tracks': fileData?.metadataTags.tracksTotal,
    Genre: fileData?.metadataTags.genre
  }

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      {children ? <DialogTrigger asChild>{children}</DialogTrigger> : null}
      <DialogContent>
        <DialogHeader>
          <DialogTitle>Info</DialogTitle>
          <DialogDescription>Metadata about the file</DialogDescription>
        </DialogHeader>
        <div className="-mx-4 no-scrollbar max-h-[50vh] overflow-y-auto px-4">
          <div className="grid grid-cols-2 gap-2">
            {Object.entries(hoverCardContentMap).map(
              ([key, value]) =>
                value && (
                  <Item variant="default" size="xs" key={key}>
                    <ItemContent>
                      <ItemTitle className="font-semibold text-xs">{key}</ItemTitle>
                      <ItemDescription className="text-xs">{value}</ItemDescription>
                    </ItemContent>
                  </Item>
                )
            )}
          </div>
          <Item size="xs" className="p-0">
            <ItemContent>
              <div className="space-y-4">
                {tracksData.map((track) => (
                  <Item
                    key={track.id}
                    variant="default"
                    className='**:data-[slot="item-title"]:text-xs **:data-[slot="item-description"]:text-xs bg-muted'
                  >
                    <ItemContent>
                      <ItemTitle className="capitalize bg-primary text-primary-foreground p-1 px-2 rounded-full text-[10px]!">
                        {track.type}
                      </ItemTitle>
                      <div className="grid grid-cols-2 gap-2">
                        {getTrackInfoFields(track).map((field) => (
                          <TrackInfoField
                            key={field.title}
                            title={field.title}
                            value={field.value}
                          />
                        ))}
                      </div>
                    </ItemContent>
                  </Item>
                ))}
              </div>
            </ItemContent>
          </Item>
        </div>
      </DialogContent>
    </Dialog>
  )
})

'use client'

import {
  ALL_FORMATS,
  BlobSource,
  Input,
  InputAudioTrack,
  InputTrack,
  MetadataTags,
  Rotation
} from 'mediabunny'

export type InputFileData = {
  audioTracks: InputAudioTrack[]
  duration: number
  format: {
    name: string
    mimeType: string
  }
  metadataTags: MetadataTags
  mimeType: string
  size: number | null
}

export type TrackData = Awaited<ReturnType<typeof getTrackData>> & {
  codedHeight?: number
  codedWidth?: number
  colorSpace?: VideoColorSpaceInit
  displayHeight?: number
  displayWidth?: number
  rotation?: Rotation
  frameRate?: number
  sampleRate?: number
  channels?: number
}

function getInput(file: File) {
  return new Input({
    formats: ALL_FORMATS,
    source: new BlobSource(file)
  })
}

export async function getFileData(file: File): Promise<InputFileData> {
  const input = getInput(file)

  let data = {}

  const [audioTracks, duration, format, metadataTags, mimeType, size] = await Promise.all([
    input.getAudioTracks(),
    input.getDurationFromMetadata(),
    input.getFormat(),
    input.getMetadataTags(),
    input.getMimeType(),
    input.source.getSizeOrNull()
  ])

  data = {
    audioTracks,
    duration,
    format: { name: format.name, mimeType: format.mimeType },
    metadataTags,
    mimeType,
    size
  }

  return data as InputFileData
}

export async function getTrackData(track: InputTrack) {
  const codec = await track.getCodec()
  const codecParamString = await track.getCodecParameterString()
  const disposition = await track.getDisposition()
  const duration = await track.getDurationFromMetadata()
  const lang = await track.getLanguageCode()
  const isAudio = track.isAudioTrack()
  const isVideo = track.isVideoTrack()
  const stats = await track.computePacketStats(100)
  const averageBitrate = stats.averageBitrate
  let trackData = {
    id: track.id,
    type: track.type,
    averageBitrate,
    codec,
    codecParamString,
    disposition,
    duration,
    lang,
    isAudio,
    isVideo
  }

  if (track.isVideoTrack()) {
    const codedHeight = await track.getCodedHeight()
    const codedWidth = await track.getCodedWidth()
    const colorSpace = await track.getColorSpace()
    const displayHeight = await track.getDisplayHeight()
    const displayWidth = await track.getDisplayWidth()
    const rotation = await track.getRotation()
    const frameRate = stats.averagePacketRate
    const videoData = {
      codedHeight,
      codedWidth,
      colorSpace,
      displayHeight,
      displayWidth,
      rotation,
      frameRate,
      averageBitrate
    }

    trackData = { ...trackData, ...videoData }
  } else if (track.isAudioTrack()) {
    const sampleRate = await track.getSampleRate()
    const channels = await track.getNumberOfChannels()
    const audioData = { sampleRate, channels }

    trackData = { ...trackData, ...audioData }
  }

  return trackData
}

export async function getTracksData(file: File) {
  const input = getInput(file)
  const tracks = await input.getTracks()

  const tracksData = []

  for (const track of tracks) {
    const trackData = await getTrackData(track)
    tracksData.push(trackData)
  }

  return tracksData
}

'use client'

import {
  EllipsisVertical,
  Image as ImageIcon,
  Info,
  Maximize,
  Music,
  Pause,
  Play,
  Volume2,
  VolumeX
} from 'lucide-react'
import { Card, CardContent, CardFooter } from '@/components/ui/card'
import { memo, useState } from 'react'
import { Slider } from '@/components/ui/slider'
import { Button } from '@/components/ui/button'
import { cn } from '@/lib/utils'
import { formatDuration } from './utils'
import { PlayerProvider, usePlayerStaticContext, usePlayerPlaybackContext } from './provider'
import { InfoModal } from './info-modal'
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuGroup,
  DropdownMenuItem,
  DropdownMenuTrigger
} from '@/components/ui/dropdown-menu'

type PlayerProps = {
  file: File
  showHTMLControls?: boolean
}

const Player = ({ file, showHTMLControls }: PlayerProps) => {
  return (
    <PlayerProvider file={file} showHTMLControls={showHTMLControls}>
      <PlayerMain />
    </PlayerProvider>
  )
}

const PlayerMain = () => {
  const { fileData } = usePlayerStaticContext()

  return (
    <Card className="w-86 md:w-120 h-71 md:h-90 max-w-full gap-0 p-0 relative overflow-hidden">
      {!fileData ? (
        <div className="absolute inset-0 bg-muted animate-pulse" />
      ) : (
        <>
          <Poster />
          <Video />
          <PlayerFooter />
        </>
      )}
    </Card>
  )
}

const Poster = memo(function Poster() {
  const { posterUrl } = usePlayerStaticContext()

  if (!posterUrl) return null

  return (
    <img
      data-posterimage
      width={100}
      height={100}
      src={posterUrl}
      alt="Poster"
      className="absolute inset-0 h-full w-full"
    />
  )
})

const Video = memo(function Video() {
  const { videoRef, showHTMLControls, posterUrl, videoUrl, setIsPlaying, type, playPause } =
    usePlayerStaticContext()

  return (
    <CardContent className="p-0 relative aspect-video" onClick={playPause}>
      {type === 'audio' && !posterUrl && (
        <div className="absolute inset-0 flex items-center justify-center bg-linear-to-b from-primary/10 to-transparent">
          <Music className="size-14 text-primary" />
        </div>
      )}
      <video
        data-video
        ref={videoRef}
        controls={showHTMLControls}
        poster={posterUrl}
        src={videoUrl}
        className="w-full h-full"
        onPlay={() => setIsPlaying(true)}
        onPause={() => setIsPlaying(false)}
        onEnded={() => setIsPlaying(false)}
      />
    </CardContent>
  )
})

const PlayerFooter = memo(function PlayerFooter() {
  const { posterUrl } = usePlayerStaticContext()

  return (
    <CardFooter
      className={cn(
        'flex min-w-0 w-full flex-col gap-2 overflow-hidden border-none relative',
        posterUrl ? 'bg-black/30 backdrop-blur-md' : 'bg-background',
        !posterUrl ? '**:data-time:text-foreground' : '**:data-time:text-white',
        '**:data-playpause:text-primary-foreground **:data-playpause:bg-primary/80',
        '**:data-controls-right:text-primary-foreground **:data-controls-right:bg-primary/80',
        !posterUrl ? '**:data-filename:text-foreground' : '**:data-filename:text-white',
        "**:data-[slot='slider-track']:bg-primary/30 **:data-[slot='slider-track']:cursor-pointer",
        "**:data-[slot='slider-range']:bg-primary/80"
      )}
    >
      <Controls />
      <ProgressBar />
      <FileName />
    </CardFooter>
  )
})

const Controls = () => {
  const { playPause, handleMute, handleCapture, type } = usePlayerStaticContext()
  const { currentTime, duration, isPlaying, isMuted } = usePlayerPlaybackContext()

  const rightControls = [
    {
      id: 'mute',
      icon: isMuted ? <VolumeX className="size-3" /> : <Volume2 className="size-3" />,
      onClick: handleMute
    },
    {
      id: 'capture',
      icon: <ImageIcon className="size-3" />,
      onClick: handleCapture
    }
  ]

  return (
    <div className="text-xs font-sans w-full grid grid-cols-3">
      <span data-time className="flex items-center">
        {formatDuration(currentTime)} / {formatDuration(duration)}
      </span>
      <span className="flex items-center justify-center">
        <Button data-playpause size="icon-xs" onClick={playPause}>
          {isPlaying ? <Pause className="size-3" /> : <Play className="size-3" />}
        </Button>
      </span>
      <div className="flex items-center justify-end gap-2">
        {rightControls.map((control) => {
          if (type === 'audio' && control.id === 'capture') {
            return null
          }
          return (
            <Button key={control.id} data-controls-right size="icon-xs" onClick={control.onClick}>
              {control.icon}
            </Button>
          )
        })}
        <MoreControls>
          <Button data-controls-right size="icon-xs">
            <EllipsisVertical className="size-3" />
          </Button>
        </MoreControls>
      </div>
    </div>
  )
}

const MoreControls = ({ children }: { children: React.ReactNode }) => {
  const { handleMaximize } = usePlayerStaticContext()
  const [infoOpen, setInfoOpen] = useState(false)

  const moreControls = [
    {
      id: 'info',
      icon: <Info className="size-3" />,
      label: 'Info'
    },
    {
      id: 'maximize',
      icon: <Maximize className="size-3" />,
      onClick: handleMaximize,
      label: 'Maximize'
    }
  ]

  return (
    <>
      <DropdownMenu>
        <DropdownMenuTrigger asChild>{children}</DropdownMenuTrigger>
        <DropdownMenuContent side="top" align="end" className="p-2">
          <DropdownMenuGroup className="space-y-1">
            {moreControls.map((control) => {
              if (control.id === 'info') {
                return (
                  <DropdownMenuItem
                    key={control.id}
                    className="text-xs cursor-pointer"
                    onSelect={() => setInfoOpen(true)}
                  >
                    {control.icon} {control.label}
                  </DropdownMenuItem>
                )
              }
              return (
                <DropdownMenuItem
                  key={control.id}
                  className="text-xs cursor-pointer"
                  onClick={control.onClick}
                >
                  {control.icon} {control.label}
                </DropdownMenuItem>
              )
            })}
          </DropdownMenuGroup>
        </DropdownMenuContent>
      </DropdownMenu>
      <InfoModal open={infoOpen} onOpenChange={setInfoOpen} />
    </>
  )
}

const ProgressBar = () => {
  const { sliderOnValueChange } = usePlayerStaticContext()
  const { progress } = usePlayerPlaybackContext()

  return (
    <Slider
      value={[progress]}
      max={100}
      onValueChange={sliderOnValueChange}
      className="flex-1 w-full"
    />
  )
}

const FileName = memo(function FileName() {
  const { fileData, file } = usePlayerStaticContext()

  const fileName = fileData?.metadataTags.title || file.name

  return (
    <span data-filename className="min-w-0 w-full truncate text-xs text-center" title={fileName}>
      {fileName}
    </span>
  )
})

export default Player

import { getFileData, InputFileData } from './mediabunny'
import { createContext, useCallback, useContext, useEffect, useMemo, useRef, useState } from 'react'
import { getType } from './utils'

type PlaybackState = {
  progress: number
  duration: number
  currentTime: number
  isPlaying: boolean
  isMuted: boolean
}

type PlayerStaticContextType = {
  file: File
  fileData: InputFileData | null
  videoRef: React.RefObject<HTMLVideoElement | null>
  posterUrl: string | undefined
  videoUrl: string | undefined
  showHTMLControls: boolean | undefined
  setIsPlaying: (isPlaying: boolean) => void
  setIsMuted: (isMuted: boolean) => void
  sliderOnValueChange: (value: number[]) => void
  playPause: () => void
  handleMute: () => void
  handleMaximize: () => void
  handleCapture: () => void
  type: 'video' | 'audio' | 'unknown'
}

const PlayerStaticContext = createContext<PlayerStaticContextType | undefined>(undefined)

const PlayerPlaybackContext = createContext<PlaybackState | undefined>(undefined)

export const PlayerProvider = ({
  children,
  file,
  showHTMLControls
}: {
  children: React.ReactNode
  file: File
  showHTMLControls: boolean | undefined
}) => {
  const [fileData, setFileData] = useState<InputFileData | null>(null)
  const videoRef = useRef<HTMLVideoElement | null>(null)
  const [playback, setPlayback] = useState<PlaybackState>({
    progress: 0,
    duration: 0,
    currentTime: 0,
    isPlaying: false,
    isMuted: false
  })
  const [videoUrl, setVideoUrl] = useState<string>()
  const [posterUrl, setPosterUrl] = useState<string>()
  const type = getType(file)

  useEffect(() => {
    const url = URL.createObjectURL(file)
    setVideoUrl(url)

    return () => URL.revokeObjectURL(url)
  }, [file])

  const image = fileData?.metadataTags.images?.[0]

  useEffect(() => {
    if (!image) {
      setPosterUrl(undefined)
      return
    }

    const url = URL.createObjectURL(
      new Blob([new Uint8Array(image.data)], {
        type: image.mimeType
      })
    )

    setPosterUrl(url)

    return () => URL.revokeObjectURL(url)
  }, [image])

  useEffect(() => {
    getFileData(file).then(setFileData)
  }, [file])

  useEffect(() => {
    const video = videoRef.current
    if (!video) return
    const syncDuration = () => {
      if (Number.isFinite(video.duration)) {
        setPlayback((prev) => ({ ...prev, duration: video.duration }))
      }
    }
    const handleTimeUpdate = () => {
      setPlayback((prev) => ({
        ...prev,
        currentTime: video.currentTime,
        progress: Number.isFinite(video.duration)
          ? (video.currentTime / video.duration) * 100
          : prev.progress
      }))
    }
    syncDuration()
    video.addEventListener('loadedmetadata', syncDuration)
    video.addEventListener('durationchange', syncDuration)
    video.addEventListener('timeupdate', handleTimeUpdate)
    return () => {
      video.removeEventListener('loadedmetadata', syncDuration)
      video.removeEventListener('durationchange', syncDuration)
      video.removeEventListener('timeupdate', handleTimeUpdate)
    }
  }, [fileData])

  const setIsPlaying = useCallback((isPlaying: boolean) => {
    setPlayback((prev) => ({ ...prev, isPlaying }))
  }, [])

  const setIsMuted = useCallback((isMuted: boolean) => {
    setPlayback((prev) => ({ ...prev, isMuted }))
  }, [])

  const sliderOnValueChange = useCallback((val: number[]) => {
    setPlayback((prev) => ({ ...prev, progress: val[0] }))
    const video = videoRef.current
    if (!video) return
    video.currentTime = (val[0] / 100) * video.duration
  }, [])

  const playPause = useCallback(() => {
    const video = videoRef.current
    if (!video) return
    if (video.paused) {
      void video.play()
    } else {
      video.pause()
    }
  }, [])

  const handleMute = useCallback(() => {
    const video = videoRef.current
    if (!video) return
    video.muted = !video.muted
    setPlayback((prev) => ({ ...prev, isMuted: video.muted }))
  }, [])

  const handleMaximize = useCallback(() => {
    videoRef.current?.requestFullscreen()
  }, [])

  const handleCapture = useCallback(() => {
    const video = videoRef.current
    if (!video) return
    video.pause()
    const canvas = document.createElement('canvas')
    canvas.width = video.videoWidth
    canvas.height = video.videoHeight
    canvas.getContext('2d')?.drawImage(video, 0, 0)
    const image = canvas.toDataURL()
    const link = document.createElement('a')
    link.href = image
    link.download = 'frame_' + file.name.split('.').slice(0, -1).join('.') + '.png'
    link.target = '_blank'
    link.click()
    link.remove()
  }, [file.name])

  const staticValue = useMemo<PlayerStaticContextType>(() => {
    return {
      file,
      fileData,
      videoRef,
      showHTMLControls,
      posterUrl,
      videoUrl,
      setIsPlaying,
      setIsMuted,
      sliderOnValueChange,
      playPause,
      handleMute,
      handleMaximize,
      handleCapture,
      type
    }
  }, [
    file,
    fileData,
    showHTMLControls,
    posterUrl,
    videoUrl,
    setIsPlaying,
    setIsMuted,
    sliderOnValueChange,
    playPause,
    handleMute,
    handleMaximize,
    handleCapture,
    type
  ])

  return (
    <PlayerStaticContext.Provider value={staticValue}>
      <PlayerPlaybackContext.Provider value={playback}>{children}</PlayerPlaybackContext.Provider>
    </PlayerStaticContext.Provider>
  )
}

export const usePlayerStaticContext = () => {
  const context = useContext(PlayerStaticContext)
  if (!context) {
    throw new Error('usePlayerStaticContext must be used within a PlayerProvider')
  }
  return context
}

export const usePlayerPlaybackContext = () => {
  const context = useContext(PlayerPlaybackContext)
  if (!context) {
    throw new Error('usePlayerPlaybackContext must be used within a PlayerProvider')
  }
  return context
}

export function formatBytes(bytes: number) {
  const sizes = ['B', 'KB', 'MB', 'GB']
  const i = Math.floor(Math.log(bytes) / Math.log(1024))
  return (bytes / Math.pow(1024, i)).toFixed(2) + ' ' + sizes[i]
}

export function formatDuration(duration: number): string {
  const totalSeconds = Math.floor(duration)

  const hours = Math.floor(totalSeconds / 3600)
  const minutes = Math.floor((totalSeconds % 3600) / 60)
  const seconds = totalSeconds % 60

  if (hours > 0) {
    return `${hours.toString().padStart(2, '0')}:${minutes
      .toString()
      .padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`
  }

  if (minutes > 0) {
    return `${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`
  }

  return `${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`
}

export const VIDEO_EXTENSIONS = [
  '.mp4',
  '.mov',
  '.avi',
  '.mkv',
  '.webm',
  '.flv',
  '.wmv',
  '.mpeg',
  '.mpg',
  '.3gp'
]

export const AUDIO_EXTENSIONS = ['.mp3', '.wav', '.ogg', '.m4a', '.aac', '.flac', 'm4a']

export function getType(file: File) {
  const extension = file.name.split('.').pop()
  if (extension && VIDEO_EXTENSIONS.includes(extension)) {
    return 'video'
  }
  if (extension && AUDIO_EXTENSIONS.includes(extension)) {
    return 'audio'
  }
  return 'unknown'
}

export function formatBitrate(bps: number): string {
  if (bps >= 1_000_000) {
    return `${(bps / 1_000_000).toFixed(2)} Mbps`
  }

  if (bps >= 1_000) {
    return `${(bps / 1_000).toFixed(0)} kbps`
  }

  return `${bps.toFixed(0)} bps`
}

export function truncateTo2Decimals(num: number): number {
  return Math.trunc(num * 100) / 100
}
